{
  "competency_groups": [
    {
      "code": "U7-C1",
      "title": "Dual Nature of Radiation and Matter",
      "description": "Understanding the particle nature of light, wave nature of matter, and their experimental evidence.",
      "competencies": [
        "Explain the dual nature of radiation through photoelectric effect observations by Hertz and Lenard.",
        "Apply Einstein's photoelectric equation to describe the particle nature of light.",
        "Describe the experimental study results supporting the wave-particle duality concept."
      ],
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Dual Nature of Radiation and Matter"
    },
    {
      "code": "U8-C1",
      "title": "Atoms",
      "description": "Analyzing atomic models, electron orbits, and spectral lines based on scattering experiments.",
      "competencies": [
        "Interpret the alpha-particle scattering experiment leading to Rutherford's model of the atom.",
        "Apply Bohr's postulates to derive expressions for radius, velocity, and energy in hydrogen orbitals."
      ],
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Atoms"
    },
    {
      "code": "U8-C2",
      "title": "Nuclei",
      "description": "Evaluating nuclear properties, binding energy concepts, and fission/fusion processes.",
      "competencies": [
        "Analyze the composition, size of nucleus, and mass-energy relation including mass defect."
      ],
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Nuclei"
    },
    {
      "code": "U9-C1",
      "title": "Materials, Devices and Simple Circuits",
      "description": "Differentiating energy bands in materials and analyzing semiconductor diode characteristics.",
      "competencies": [
        "Distinguish between conductors, semiconductors, and insulators based on energy band theory."
      ],
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Materials, Devices and Simple Circuits"
    }
  ]
}
